b:if.script:
(function(){
  var m = document.getElementById('og-image');
  if (m) {
    var url = m.getAttribute('content');
    // Reemplazar cualquier /sXX-c/ o /sXX/ de Blogger por /s1200/
    url = url.replace(/\/s\d+(-c)?\//, '/s1200/');
    m.setAttribute('content', url);
  }
})();

