body.script:
//
(function() {
  function initCards() {
    var cards = document.querySelectorAll('.post-card-compact[data-estado]');
    cards.forEach(function(card) {
      var estado = card.getAttribute('data-estado');
      if (estado === 'EN-VIVO')    card.classList.add('estado-en-vivo-card');
      if (estado === 'PROXIMO')    card.classList.add('estado-proximo-card');
      if (estado === 'FINALIZADO') card.classList.add('estado-finalizado-card');

    });
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initCards);
  } else {
    initCards();
  }
})();

